muclient.script:
require "movewindow"
local MIP_ID = "9a8b3c5d1e2f4a6b8c0d2e4f" local MARKET_ID = "b2c3d4e5f60718293a4b5c6d" -- ThreeS_Market, for live prices (settler upkeep) local WIN = "vikingstatus_" .. GetPluginID() local W, H = 560, 560 local windowinfo local visible = (GetVariable("visible") ~= "0") local tab = GetVariable("tab") or "Stats" local prev_rndz = nil -- last seen RNDZ (round counter) local last_fight = tonumber(GetVariable("last_fight")) or 0 -- rounds the previous combat lasted -- Modrsokn: a combat ability with a 3-minute cooldown. The MIP feed doesn't expose it, so we -- start a local timer from the "turn the rage inward" line and count down on the Stats tab. local MORDSOKN_CD = 180 local mordsokn_at = tonumber(GetVariable("mordsokn_at")) or 0 local mordsokn_ticking = false local TABS = { "Stats", "City", "Builds", "Production", "People", "Settlers", "Holds", "Sea", "Voyage", "Map", "Plan", "Mission", "Feeds" }
local C = { bg = 0x201510, panel = 0x2A1C14, border = 0x604020, label = 0xD0D0D0, dim = 0x808080, text = 0xF0F0F0, head = 0x40C0FF, good = 0x60E060, warn = 0x40C0FF, bad = 0x5050F0, tabbg = 0x301E12, tabsel = 0x604020, title = 0x402818, }
-- terrain char -> colour (BGR), decoded from the live VMR rows local TERRAIN = { ["."] = 0x101010, -- void / walls ["t"] = 0x606060, ["T"] = 0x707070, -- tundra grey ["h"] = 0x20C0C0, ["H"] = 0x20C0C0, -- hills yellow ["A"] = 0x3030D0, -- mountains red ["f"] = 0x208020, ["F"] = 0x30A030, -- forest ["p"] = 0x60C060, -- plains ["W"] = 0xD0A000, ["w"] = 0xD0A000, ["~"] = 0xD0A000, -- water ["r"] = 0x181818, ["="] = 0x303030, -- road / bridge ["P"] = 0x909090, -- gate / passage ["L"] = 0x2080E0, -- lin hold ["S"] = 0x40C0E0, -- settlement ["C"] = 0x2020C0, -- capital ["R"] = 0xC060C0, -- ruins ["M"] = 0x2020C0, -- Midgard (capital) ["*"] = 0xE060E0, -- point of interest ["X"] = 0xFFFFFF, -- you (feed marker) }
local function loc_color(t) t = (t or ""):lower() if t:find("cap") then return 0x2020E0 elseif t:find("lin") then return 0x2080E0 elseif t:find("set") then return 0x40C0E0 elseif t:find("mentor") then return 0x60E060 elseif t:find("blot") then return 0x40E080 elseif t:find("farm") then return 0x40A040 elseif t:find("seer") then return 0xE060C0 elseif t:find("ruin") then return 0xC060C0 else return 0xD0D0D0 end end
local function parse_locs(s) local out = {} if not s or s == "" then return out end for entry in s:gmatch("[^;]+") do local f = {} for tok in entry:gmatch("[^|]*") do if tok ~= "" or #f > 0 then f[#f + 1] = tok end end local i = 1 while i + 3 <= #f do if tonumber(f[i + 2]) and tonumber(f[i + 3]) then out[#out + 1] = { type = f[i], name = f[i + 1], x = tonumber(f[i + 2]), y = tonumber(f[i + 3]) } i = i + 4 else i = i + 1 end end end return out end
local function grad(pct) if pct > 100 then return 0xFFC040 end if pct < 0 then pct = 0 end local r, g if pct >= 50 then r = math.floor(255 * (100 - pct) / 50); g = 220 else r = 255; g = math.floor(220 * pct / 50) end return g * 256 + r end
local function num(s) return tonumber(s) or 0 end
local function split(s, sep) local out = {} if not s or s == "" then return out end local pat = "([^" .. sep .. "]*)" .. sep .. "?" local pos = 1 while pos <= #s + 1 do local st, en, cap = s:find(pat, pos) if not st then break end out[#out + 1] = cap if en < st then break end pos = en + 1 end if out[#out] == "" then out[#out] = nil end return out end
local function clean(s) return (s or ""):gsub("grey:", ""):gsub("gray:", ""):gsub("red:", ""):gsub("green:", ""):gsub("blue:", ""):gsub("yellow:", "") end
local function getvars() local function gv(k) return GetPluginVariable(MIP_ID, k) or "" end local vmip = {} for line in gv("vmip_ser"):gmatch("[^\n]+") do local k, v = line:match("^([^=]+)=(.*)$") if k then vmip[k] = v end end return { hp = num(gv("hp")), hpmax = num(gv("hpmax")), sp = num(gv("sp")), spmax = num(gv("spmax")), enemy_name = gv("enemy_name"), enemy_hp = gv("enemy_hp"), gline1 = gv("gline1"), gline2 = gv("gline2"), uptime = gv("uptime"), lag = gv("lag"), }, vmip end
-- ============ auto sea-navigation (tour discovered chart features) ============ -- Diverts the current voyage toward newly-revealed islands / wrecks / objectives, nearest first. local sea_nav = { on = (GetVariable("seanav") == "1"), -- default OFF (safety) target = nil, -- { coord, r, c } we've queued a course to visited = {}, -- coords already toured this voyage voyage = "", -- voyage id, to reset the tour on a new voyage resolve = GetVariable("seanav_resolve") or "hold,evade?hull<40,hunt,ration,salvage,resupply?supplies<50,plunder", -- keyword[?cond] list last_cmd_at = 0, } local SEANAV_TARGETS = { I = true, W = true, X = true } -- island / wreck / objective -- scan the voyage chart: returns the target features {coord,r,c,sym} and the ship's cell {r,c} local function sea_chart_scan(vmip) local h = num(split(vmip.VCHH or "", "|")[2] or "") if h <= 0 then return nil, nil end local feats, ship = {}, nil for r = 0, h - 1 do local rowstr = vmip[string.format("VCR%02d", r)] if rowstr then for c = 1, #rowstr do local s = rowstr:sub(c, c) if s == "S" then ship = { r = r, c = c } elseif SEANAV_TARGETS[s] then feats[#feats + 1] = { coord = string.char(65 + r) .. string.format("%02d", c), r = r, c = c, sym = s } end end end end return feats, ship end -- destination of the currently queued voyage course (last waypoint of VQPATH), as a coord local function vqpath_dest(s) local nums = {} for n in (s or ""):gmatch("%d+") do nums[#nums + 1] = tonumber(n) end if #nums < 2 then return nil end local col, row = nums[#nums - 1], nums[#nums] -- VQPATH pairs are col,row; last = destination return string.char(65 + row) .. string.format("%02d", col) end
-- number to commit on patrol: a user override if set, else the last patrol's count local function patrol_number(vmip) local override = tonumber(GetVariable("patrol_num")) if override then return override end return tonumber((split(vmip.PATROL or "", "|"))[1]) end
local GOODS_NAME = { t = "timber", i = "iron", g = "grain", f = "furs", h = "fish", m = "mead", a = "sunstone", r = "runeston", s = "spoils" }
-- "0|Name|a|b;1|Name2|..." -> map idx -> field list local function parse_idx_table(s) local out = {} for entry in (s or ""):gmatch("[^;]+") do local f = split(entry, "|") local i = tonumber(f[1]) if i then out[i] = f end end return out end
-- known settlements (from the in-game Settlements list); vikloc overrides local DEFAULT_LOCNAMES = { ["35|17"] = "Midgard", ["17|9"] = "Lodbrok's Hold", ["55|7"] = "Eiriksby", ["13|17"] = "Imaird", ["57|17"] = "Holmgard", ["37|7"] = "Hafrfjord", ["33|27"] = "Uppsala", ["19|25"] = "Borgarfjord", ["53|25"] = "Vestergotland", ["23|21"] = "Sverkersby", ["49|9"] = "Ericsgard", ["15|23"] = "Birka", ["55|21"] = "Lejre", ["25|9"] = "Nidaros", -- special sites keep fixed grid positions (they did not shift with the grid expansion). -- Seer's cell (19|25) now coincides with Borgarfjord above; its type is still set below. ["50|27"] = "Jarl", ["51|16"] = "Berserker", ["3|28"] = "Blot", -- grove, 3s + 16w of Borgarfjord (19|25) }
-- trade-hold index -> city name (what you trade against in-game). VREP gives -- the lineage/clan name instead, which is confusing, so map it to the city. local HOLDCITY = { [0] = "Midgard", [1] = "Lodbrok's Hold", [2] = "Eiriksby", [3] = "Imaird", [4] = "Holmgard", [5] = "Hafrfjord", [6] = "Uppsala", [7] = "Borgarfjord", [8] = "Vestergotland", [9] = "Sverkersby", [10] = "Ericsgard", [11] = "Birka", [12] = "Lejre", [13] = "Nidaros", }
-- type labels for special places that are not travel towns local DEFAULT_LOCTYPE = { ["50|27"] = "Mentor", ["19|25"] = "Seer", ["51|16"] = "Mentor", ["3|28"] = "Blot", }
-- ====================== City Plan (CP* feed) ====================== -- role -> colour (BGR), matching the in-game "coloured by role" legend local PLAN_ROLE = { prod = 0x40E040, -- producers (green) ind = 0x3040E0, -- industry (red) grim = 0x2828A0, -- grim (maroon) trade = 0xE0D040, -- trade (cyan) cult = 0xE060E0, -- culture (magenta) home = 0xE0E0E0, -- homes (white) throne= 0x40D0FF, -- throne (gold) } -- building shortcut letter -> { name, role }. Letter is what 'vplan place <L> <cell>' expects. local PLAN_BLD = { { "F", "Farm", "prod" }, { "M", "Mine", "prod" }, { "K", "Smithy", "ind" }, { "E", "Beacon", "grim" }, { "P", "Apiary", "prod" }, { "I", "Fishery", "prod" }, { "S", "Smelter", "ind" }, { "N", "Tannery", "ind" }, { "R", "Armoury", "ind" }, { "g", "Garrison", "grim" }, { "V", "Weaponry", "ind" }, { "d", "Mead hall", "throne"}, { "B", "Bakehouse", "ind" }, { "W", "Warehouse", "trade" }, { "h", "Longhouse", "home" }, { "Z", "Goldsmith", "ind" }, { "k", "Skald hall", "cult" }, { "y", "Thrall pen", "grim" }, { "L", "Lumber yard", "prod" }, { "C", "Mead cellar", "ind" }, { "O", "Courier post", "trade" }, { "X", "Shadow house", "grim" }, { "T", "Trading post", "trade" }, { "D", "Training yard", "grim" }, { "u", "Muster ground", "grim" }, { "H", "Settler plots", "home" }, { "G", "Salting house", "ind" }, { "U", "Furriers lodge","ind" }, { "o", "Workyards", "ind" }, { "l", "Law stone", "cult" }, { string.char(254), "Poorhouse", "cult" }, { "b", "Watch posts", "grim" }, { "v", "Foundry row", "ind" }, { "r", "Granary mill", "ind" }, { "e", "Weaving hall", "ind" }, { "w", "Quarry works", "prod" }, { "i", "Midwife house", "cult" }, { "a", "Market stalls", "trade" }, { "n", "Fishing wharf", "cult" }, { "t", "Timberward yd", "trade" }, { "s", "Shipwrights yd","cult" }, } -- lookup: letter -> {name, role, idx} (idx = position in the 3s_cityicons.png sprite sheet) local PLAN_BY_L = {} for i, b in ipairs(PLAN_BLD) do PLAN_BY_L[b[1]] = { name = b[2], role = b[3], idx = i - 1 } end local PLAN_ICON_COLS = 8 -- sprite sheet columns; cell = 22px local cp_img = nil -- nil = not tried, true/false = load result local function cp_load_image() if cp_img == nil then cp_img = (WindowLoadImage(WIN, "cityicons", GetPluginInfo(GetPluginID(), 20) .. "3s_cityicons.png") == 0) end return cp_img end -- terrain chars (anything else in an inner cell is a placed building letter) -- { label, glyph/text colour, tile fill colour } -- fill is used by the "tiles" style local PLAN_TERRAIN = { ["."] = { "plain", 0x8A8A8A, 0x484848 }, ["f"] = { "woods", 0x70E070, 0x246E24 }, ["H"] = { "hill", 0x98C0DC, 0x50708C }, ["w"] = { "river", 0xF0B860, 0x9A5C1C }, ["c"] = { "coast", 0xD8D868, 0x6A6A20 }, ["M"] = { "wall", 0xB0B0B0, 0x585858 }, ["W"] = { "wall", 0xA0A0A0, 0x4E4E4E }, ["G"] = { "gate", 0x60E0FF, 0x466C88 }, ["B"] = { "gate", 0x60E0FF, 0x466C88 }, } local plan_sel = nil -- currently selected building letter for click-to-place local plan_style = GetVariable("plan_style") or "text" -- "text" | "tiles"
-- The MIP feed only publishes the MOST-RECENTLY placed building (CPB) plus a count (CPLAN[3]); -- it never sends the full list. So we remember placements ourselves as each one broadcasts, and -- persist them. cp_placed["col,row"] = { col,row,w,h,letter,name } (keyed by the anchor cell). local cp_placed = {} local function cp_load() cp_placed = {} for e in (GetVariable("cp_placed") or ""):gmatch("[^\n]+") do local col, row, w, h, letter, name = e:match("^(%d+)|(%d+)|(%d+)|(%d+)|([^|]*)|(.*)$") if col then cp_placed[col .. "," .. row] = { col = tonumber(col), row = tonumber(row), w = tonumber(w), h = tonumber(h), letter = letter, name = name } end end end local function cp_save() local out = {} for _, b in pairs(cp_placed) do out[#out + 1] = table.concat({ b.col, b.row, b.w, b.h, b.letter, b.name }, "|") end SetVariable("cp_placed", table.concat(out, "\n")) end local function cp_count() local n = 0; for _ in pairs(cp_placed) do n = n + 1 end; return n end -- record the building currently in CPB (idempotent: adding the same one twice is harmless) local function cp_accumulate(cpb) local changed = false for entry in (cpb or ""):gmatch("[^;]+") do local _, col, row, w, h, _, letter, name = entry:match("^([^|]*)|(%d+)|(%d+)|(%d+)|(%d+)|([^|]*)|([^|]*)|(.*)$") if col and not cp_placed[col .. "," .. row] then cp_placed[col .. "," .. row] = { col = tonumber(col), row = tonumber(row), w = tonumber(w), h = tonumber(h), letter = letter, name = name } changed = true end end if changed then cp_save() end end cp_load()
-- Full resync from the in-game 'vplan' output (the feed only sends the latest placement). The -- grid is framed; each lettered row has 12 inner cells between two '#' border columns. Inside the -- buildable grid the only terrain glyphs are . f ^, so any letter that maps to a building IS one. local cp_scan, cp_capturing = {}, false function cp_vplan_start() cp_capturing = true; cp_scan = {} end function cp_vplan_row(letter, rowstr) if not cp_capturing then return end local toks = {} for t in rowstr:gmatch("%S+") do toks[#toks + 1] = t end local h1, h2 for i = 1, #toks do if toks[i] == "#" then if not h1 then h1 = i elseif not h2 then h2 = i end end end if not (h1 and h2) then return end local row = string.byte(letter) - 65 for c = 1, 12 do local ch = toks[h1 + c] if ch and PLAN_BY_L[ch] then cp_scan[(c - 1) .. "," .. row] = { col = c - 1, row = row, w = 1, h = 1, letter = ch, name = PLAN_BY_L[ch].name } end end end function cp_vplan_end() if not cp_capturing then return end cp_capturing = false -- group adjacent same-letter cells into one building (a 2x2 warehouse shows as W in four cells -- but is ONE building). Without this the tracked count exceeds the game's and the desync guard -- in OnPluginBroadcast wrongly wipes the list on the next feed tick. local seen, built = {}, {} for k, v in pairs(cp_scan) do if not seen[k] then local c0, r0 = k:match("^(%d+),(%d+)$"); c0, r0 = tonumber(c0), tonumber(r0) local minc, maxc, minr, maxr = c0, c0, r0, r0 local stack = { { c0, r0 } }; seen[k] = true while #stack > 0 do local cell = table.remove(stack); local cc, rr = cell[1], cell[2] if cc < minc then minc = cc end; if cc > maxc then maxc = cc end if rr < minr then minr = rr end; if rr > maxr then maxr = rr end for _, d in ipairs({ { 1, 0 }, { -1, 0 }, { 0, 1 }, { 0, -1 } }) do local nk = (cc + d[1]) .. "," .. (rr + d[2]) if cp_scan[nk] and cp_scan[nk].letter == v.letter and not seen[nk] then seen[nk] = true; stack[#stack + 1] = { cc + d[1], rr + d[2] } end end end built[minc .. "," .. minr] = { col = minc, row = minr, w = maxc - minc + 1, h = maxr - minr + 1, letter = v.letter, name = v.name } end end cp_placed = built cp_save() ColourNote("cyan", "", "[plan] synced " .. cp_count() .. " buildings from vplan") vik_draw() end
-- town <-> Midgard base routes (extracted from the old TinTin aliases); -- any pair is chained as <From>Mid + Mid<To> local ROUTES = { BirMid = { "leave", "s", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "n", "n", "enter" }, -- Blot routes via Borgarfjord: Mid->Bor (leave,s8,w16) then Bor->Blot (s3,w16), no grove entry BlotMid = { "e","e","e","e","e","e","e","e","e","e","e","e","e","e","e","e", "n","n","n", "e","e","e","e","e","e","e","e","e","e","e","e","e","e","e","e", "n","n","n","n","n","n","n","n", "enter" }, BorMid = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "n", "n", "n", "n", "enter" }, EirMid = { "leave", "w", "e", "e", "s", "s", "s", "s", "s", "s", "w", "w", "s", "e", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, EriMid = { "leave", "w", "w", "s", "s", "s", "s", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, HafMid = { "leave", "e", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "w", "w", "w", "enter" }, HolMid = { "leave", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, ImaMid = { "leave", "e", "s", "s", "s", "s", "s", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "n", "enter" }, LerMid = { "leave", "n", "n", "n", "n", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, LodMid = { "leave", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "n", "enter" }, MidBir = { "leave", "s", "s", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "n", "enter" }, MidBlot = { "leave", "s","s","s","s","s","s","s","s", "w","w","w","w","w","w","w","w","w","w","w","w","w","w","w","w", "s","s","s", "w","w","w","w","w","w","w","w","w","w","w","w","w","w","w","w" }, MidBor = { "leave", "s", "s", "s", "s", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, MidEir = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "w", "n", "e", "e", "n", "n", "n", "n", "n", "n", "w", "w", "e", "enter" }, MidEri = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "n", "n", "n", "n", "e", "e", "enter" }, MidHaf = { "leave", "e", "e", "e", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "w", "enter" }, MidHol = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "enter" }, MidIma = { "leave", "s", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "n", "n", "n", "n", "n", "w", "enter" }, MidLer = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "s", "s", "s", "s", "enter" }, MidLod = { "leave", "s", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "enter" }, MidNid = { "leave", "s", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "enter" }, MidSeer = { "leave", "w", "w", "w", "s", "s", "s", "s", "enter" }, MidSve = { "leave", "s", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "n", "enter" }, MidUpp = { "leave", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "w", "w", "enter" }, MidVas = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "s", "s", "s", "s", "s", "s", "s", "s", "e", "e", "enter" }, NidMid = { "leave", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "n", "enter" }, SeerMid = { "leave", "n", "n", "n", "n", "e", "e", "e", "enter" }, SveMid = { "leave", "s", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "n", "enter" }, UppMid = { "leave", "e", "e", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "enter" }, VasMid = { "leave", "w", "w", "n", "n", "n", "n", "n", "n", "n", "n", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, }
local function vik_send_route(origin, dest) local cmds = {} if origin ~= "Mid" then local leg = ROUTES[origin .. "Mid"] if not leg then return false end for _, c in ipairs(leg) do cmds[#cmds + 1] = c end end if dest ~= "Mid" then local leg = ROUTES["Mid" .. dest] if not leg then return false end for _, c in ipairs(leg) do cmds[#cmds + 1] = c end end for _, c in ipairs(cmds) do Send(c) end return true end
-- travel codes per settlement (routes are built into this plugin now) local TRAVEL_CODE = { ["35|17"] = "Mid", ["17|9"] = "Lod", ["55|7"] = "Eir", ["13|17"] = "Ima", ["57|17"] = "Hol", ["37|7"] = "Haf", ["33|27"] = "Upp", ["19|25"] = "Bor", ["53|25"] = "Vas", ["23|21"] = "Sve", ["49|9"] = "Eri", ["15|23"] = "Bir", ["55|21"] = "Ler", ["25|9"] = "Nid", }
-- Special sites that are travelable but NOT lineage towns. Kept out of TRAVEL_CODE so they keep -- their own map type/colour (e.g. Blot), but still route via <From>Mid + Mid<To> and are clickable. local SPECIAL_TRAVEL = { ["3|28"] = "Blot" } local function travel_code(key) return TRAVEL_CODE[key] or SPECIAL_TRAVEL[key] end
-- user-named map locations (vikloc x y name) local locnames = {} do local s = GetVariable("locnames") if s then for line in s:gmatch("[^\n]+") do local x, y, n = line:match("^(%-?%d+)|(%-?%d+)|(.*)$") if x then locnames[x .. "|" .. y] = n end end end end
local function locname(x, y) local key = x .. "|" .. y return locnames[key] or DEFAULT_LOCNAMES[key] end
function vik_setloc(x, y, name) name = (name or ""):gsub("^%s+", ""):gsub("%s+$", "") local key = x .. "|" .. y if name == "" then locnames[key] = nil else locnames[key] = name end local out = {} for k, n in pairs(locnames) do out[#out + 1] = k .. "|" .. n end SetVariable("locnames", table.concat(out, "\n")) Note("[viking] location (" .. x .. "," .. y .. "): " .. (name == "" and "(cleared)" or name)) vik_draw() end
function vik_travel_click(flags, id) local x, y = id:match("^trav_(%-?%d+)|(%-?%d+)$") if not x then return end local destkey = x .. "|" .. y local dest = travel_code(destkey) if not dest then return end local destname = locname(tonumber(x), tonumber(y)) or dest local rh = false if bit and bit.band then rh = bit.band(flags, 0x20) ~= 0 end if rh then SetVariable("curtown", destkey) SetVariable("curtown_time", tostring(os.time())) Note("[viking] current location set: " .. destname) return end -- two origin candidates: the live map position and the town we last -- travelled to. The map feed lags behind movement, so the NEWER of -- the two wins. local my, vmip = getvars() local hd = split(vmip.VMAPH or "", "|") local px, py = tonumber(hd[3]), tonumber(hd[4]) local live, livekey if px and py then for k, code in pairs(TRAVEL_CODE) do local tx, ty = k:match("^(%-?%d+)|(%-?%d+)$") if math.abs(px - tx) <= 2 and math.abs(py - ty) <= 2 then live, livekey = code, k break end end if not live then -- also match travelable special sites (Blot) for k, code in pairs(SPECIAL_TRAVEL) do local tx, ty = k:match("^(%-?%d+)|(%-?%d+)$") if math.abs(px - tx) <= 2 and math.abs(py - ty) <= 2 then live, livekey = code, k break end end end end local rem, remkey local ck = GetVariable("curtown") if ck and travel_code(ck) then rem, remkey = travel_code(ck), ck end -- click-travel knowledge is authoritative: the map feed only updates on -- the guild tick and lags far behind actual movement. Only discard the -- remembered town if the feed has clearly shown us somewhere ELSE for a -- while (manual trekking since the last click). if rem and px and py then local vm_time = tonumber(GetPluginVariable(MIP_ID, "vmaph_time")) or 0 local ct_time = tonumber(GetVariable("curtown_time")) or 0 if vm_time > ct_time + 180 then local tx, ty = remkey:match("^(%-?%d+)|(%-?%d+)$") if math.abs(px - tx) > 4 or math.abs(py - ty) > 4 then rem, remkey = nil, nil -- wandered off since the last click end end end local origin, originkey if rem then origin, originkey = rem, remkey elseif live then origin, originkey = live, livekey end if not origin then Note("[viking] can't tell where you are - right-click the town you're in, then click your destination") return end if originkey == destkey then Note("[viking] you are already at " .. destname) return end Note("[viking] travelling " .. origin .. " -> " .. dest .. " (" .. destname .. ")") if not vik_send_route(origin, dest) then Note("[viking] no route known for " .. origin .. " -> " .. dest) return end SetVariable("curtown", destkey) SetVariable("curtown_time", tostring(os.time())) end
-- ---------------- drawing helpers ---------------- local ly = 0 -- line cursor local function nl(dy) ly = ly + (dy or 14) end local function txt(x, s, col, font) WindowText(WIN, font or "f", s or "", x, ly, 0, 0, col or C.text) end local function header(s) txt(10, s, C.head, "fb"); nl(15) end
local function bar(x1, x2, label, cur, max, showtext) txt(10, label, C.label) WindowRectOp(WIN, 2, x1, ly + 1, x2, ly + 13, C.panel) local pct = 0 if max > 0 then pct = cur * 100 / max end local fill = math.floor((x2 - x1 - 2) * math.min(pct, 100) / 100) if fill > 0 then WindowRectOp(WIN, 2, x1 + 1, ly + 2, x1 + 1 + fill, ly + 12, grad(pct)) end WindowRectOp(WIN, 1, x1, ly + 1, x2, ly + 13, C.border) txt(x2 + 8, showtext, C.text) nl(17) end
-- ---------------- tab renderers ---------------- local function draw_stats(my, vmip) bar(70, 330, "HP", my.hp, my.hpmax, my.hp .. "/" .. my.hpmax) bar(70, 330, "Seid", num(vmip.SEID), num(vmip.MSEID), (vmip.SEID or "?") .. "/" .. (vmip.MSEID or "?")) bar(70, 330, "Vig", num(vmip.VIG), num(vmip.MVIG), (vmip.VIG or "?") .. "/" .. (vmip.MVIG or "?")) bar(70, 330, "Rad", num(vmip.RAD), num(vmip.MRAD), (vmip.RAD or "?") .. "/" .. (vmip.MRAD or "?")) if my.enemy_name ~= "" then bar(70, 330, "Enemy", num(my.enemy_hp), 100, my.enemy_hp .. "% " .. my.enemy_name:sub(1, 24)) else txt(10, "Enemy: -", C.dim); nl(17) end nl(6) header("-- War --") txt(10, string.format("God %s > %s next %ss", vmip.GOD_POWER or "?", vmip.GOD_POWER_FOCUS or "?", vmip.GOD_POWER_NEXT or "?")); nl() txt(10, string.format("Raid %s Blot %s", vmip.RAID or "?", (vmip.BLOT or "?"):sub(1, 16))); nl() nl(6) header("-- " .. (vmip.LIN or "?") .. " GLvl " .. (vmip.GLVL or "?") .. " --") local sub_lbl = string.format("Sub %s Daler ", vmip.SUB or "?") txt(10, sub_lbl) WindowText(WIN, "f", vmip.DALER or "?", 10 + WindowTextWidth(WIN, "f", sub_lbl), ly, 0, 0, C.good) nl() txt(10, string.format("Kap %s Aud %s Vis %s Soemd %s", vmip.KAP or "?", vmip.AUD or "?", vmip.VIS or "?", vmip.SOE or "?")); nl() txt(10, string.format("VKxp %s New %s Reg %s Tick %ss", vmip.VKXP or "?", vmip.VMNEW or "?", vmip.VMREG or "?", vmip.NEXTTICK or "?")); nl() local wx = split(vmip.WEATHER or "", "|") local dc = split(vmip.DCYCLE or "", "|") txt(10, string.format("Weather %s/%s Cycle %s", wx[1] or "?", wx[2] or "?", dc[1] or "?"), C.dim); nl() nl(6) -- NOTE: two builds exist - this tracked file (plain) and the git-ignored -- 3S_VikingStatus_Colors.xml (spell colours). Apply any edit to BOTH unless -- told otherwise; the colours block lives just above draw_stats in the copy. local stfx = clean(vmip.STFX or ""):gsub("[%[%]]", "") if stfx ~= "" then -- active spell effects, wrapped over up to 2 rows so more can fit local x, rows = 10, 1 for tok in stfx:gmatch("%S+") do local w = (#tok + 1) * 7 if x > 10 and x + w > W - 12 then if rows >= 2 then break end nl(); x = 10; rows = rows + 1 end WindowText(WIN, "f", tok, x, ly, 0, 0, C.warn) x = x + w end nl() end nl(6) header("-- Combat --") txt(10, "Fury " .. clean(vmip.FURY or ""):sub(1, 12)); nl() txt(10, string.format("Threk %s / %s Chain %s Depth %s", vmip.THREK or "?", vmip.MTHREK or "?", vmip.CHAIN or "?", vmip.BSDEPTH or "?")); nl() txt(10, "Rounds " .. (vmip.RNDZ or "?")); nl() txt(10, "Last fight " .. (last_fight > 0 and tostring(last_fight) or "-")); nl() txt(10, string.format("Ledung %s / %s uses", vmip.LDNG or "?", vmip.MLDNG or "?")); nl() local mleft = MORDSOKN_CD - (os.time() - mordsokn_at) if mordsokn_at > 0 and mleft > 0 then txt(10, string.format("Modrsokn %d:%02d", math.floor(mleft / 60), mleft % 60), C.warn); nl() else txt(10, "Modrsokn ready", C.good); nl() end nl(6) header("-- Patrol --") if (vmip.PATROL or "") == "" then txt(10, "none on patrol", C.dim); nl() else local p = split(vmip.PATROL or "", "|") local mins = tonumber(p[2]) and (math.floor(num(p[2]) / 60) .. "m left") or "" txt(10, string.format("Hirdmadrs %s %s", p[1] or "?", mins)); nl() end -- click to commit a new patrol; number defaults to the last patrol's count local pn = patrol_number(vmip) local clbl = "Commit patrol: " .. (pn or "?") txt(10, clbl, C.good) local cw = WindowTextWidth(WIN, "f", clbl) WindowAddHotspot(WIN, "patrol_commit", 10, ly, 10 + cw, ly + 12, "", "", "vik_patrol_commit", "", "", "Send: vpatrol commit " .. (pn or "?"), 1, 0) local chx = 10 + cw + 14 txt(chx, "[change]", C.head) WindowAddHotspot(WIN, "patrol_setnum", chx, ly, chx + WindowTextWidth(WIN, "f", "[change]"), ly + 12, "", "", "vik_patrol_setnum", "", "", "Set a custom number to commit", 1, 0) nl() end
local function draw_settlers(my, vmip) header("-- Settlement --") txt(10, string.format("Blot %s Sproj %s", (vmip.BLOT or "?"):sub(1, 14), (vmip.SPROJ ~= "" and vmip.SPROJ) or "-")); nl() nl(4)
-- Everything below is driven by the SEVENTS tick report (authoritative plain-text feed). -- The old SETTLERX slot layout changed -- the game moved mood / tax / sentiment out of the -- numeric slots and into the SEVENTS text -- so we parse the report instead of guessing slots. -- SETTLERS is only used as a fallback for pop / water when no tick report has arrived yet. local s = split(vmip.SETTLERS or "", "|") local sts, srep = (vmip.SEVENTS or ""):match("^(%d+)|(.*)$") srep = srep or "" local pop = srep:match("Settlers:%s*(%d+)") or s[1] local moodname, mood = srep:match("Mood:%s*(%a+)%s*%((%d+)/100%)") local sentiment = srep:match("Sentiment:%s*([%+%-]?%d+)") local inc, tax, comm = srep:match("Income:%s*%+?(%d+)%s*daler%s*%(tax%s*(%d+)%s*%+%s*community%s*(%d+)%)") local wr, wm = srep:match("Water reserve:%s*(%d+)/(%d+)") if not wr then wr = s[4] end
header("-- Settlers --") txt(10, string.format("Population %s Mood %s %s/100 Sentiment %s", pop or "?", moodname or "?", mood or "?", sentiment or "?")); nl() local moodn = tonumber(mood) if moodn then WindowRectOp(WIN, 2, 150, ly + 1, 400, ly + 12, C.panel) local fill = math.floor(248 * math.min(moodn, 100) / 100) if fill > 0 then WindowRectOp(WIN, 2, 151, ly + 2, 151 + fill, ly + 11, grad(moodn)) end WindowRectOp(WIN, 1, 150, ly + 1, 400, ly + 12, C.border) nl(16) end if wr then txt(10, string.format("Water reserve %s%s", wr, wm and ("/" .. wm) or ""), (wm and tonumber(wr) * 2 >= tonumber(wm)) and C.text or C.warn); nl() end nl(4)
header(sts and ("-- Economy (tick " .. os.date("%H:%M", tonumber(sts)) .. ") --") or "-- Economy --") if inc then txt(10, string.format("Income +%s d/tick (tax %s + community %s)", inc, tax, comm), C.good); nl() end -- settler upkeep: the game's actual per-tick daler cost (UPKEEP = cat|cat|...|total) local up = split(vmip.UPKEEP or "", "|") local upkeep = tonumber(up[#up]) if upkeep then local net = (tonumber(inc) or 0) - upkeep txt(10, string.format("Upkeep %d d/tick Net %s%d", upkeep, net >= 0 and "+" or "", net), net >= 0 and C.good or C.bad); nl() end local nextt = tonumber(vmip.NEXTTICK) if nextt then local h, m = math.floor(nextt / 3600), math.floor((nextt % 3600) / 60) txt(10, "Next tick in " .. (h > 0 and (h .. "h " .. m .. "min") or (m .. "min")), C.dim); nl() end nl(4)
-- last-tick demand: green when fully met, red when it fell short if srep ~= "" then header("-- Demand (last tick) --") local cx = { Food = 10, Spoils = 150, Mead = 280 } local shown = false for _, k in ipairs({ "Food", "Spoils", "Mead" }) do local got, want = srep:match(k .. ":%s*consumed%s*(%d+)/(%d+)") if got then shown = true txt(cx[k], string.format("%s %s/%s", k, got, want), (tonumber(got) >= tonumber(want)) and C.good or C.bad) end end if shown then nl() else txt(10, "no tick report yet", C.dim); nl() end nl(4) end header("-- Civic --") local civ = {} for entry in (vmip.SCIVICS or ""):gmatch("[^;]+") do local name, lvl = entry:match("^(.-):(%d+)$") if name then name = name:gsub("_", " "):gsub("(%a)([%w]*)", function(a, b) return a:upper() .. b end) civ[#civ + 1] = name .. " T" .. lvl end end if #civ == 0 then txt(10, "none", C.dim); nl() else table.sort(civ) local rows = math.ceil(#civ / 2) for i = 1, rows do WindowText(WIN, "f", civ[i] or "", 10, ly, 0, 0, C.text) WindowText(WIN, "f", civ[i + rows] or "", 170, ly, 0, 0, C.text) nl(13) end end nl(4) header("-- Consumption (per cycle) --") local cons = {} for entry in (vmip.SCONSUME or ""):gmatch("[^;]+") do local res, amt = entry:match("^(.-):(%-?%d+)$") if res then cons[#cons + 1] = res .. " " .. amt end end txt(10, #cons > 0 and table.concat(cons, " ") or "none", #cons > 0 and C.text or C.dim); nl() end
local function draw_builds(my, vmip) local bh = "-- Buildings Daler " local dal = vmip.DALER or "?" txt(10, bh, C.head, "fb") local bx = 10 + WindowTextWidth(WIN, "fb", bh) WindowText(WIN, "fb", dal, bx, ly, 0, 0, C.good) txt(bx + WindowTextWidth(WIN, "fb", dal), " --", C.head, "fb") nl(15) -- tier -> colour (BGR): T1 white, T2 teal, T3 blue, T4 yellow, T5 red local TIERCOL = { ["1"] = 0xF0F0F0, ["2"] = 0xC0C000, ["3"] = 0xFF8040, ["4"] = 0x20E0F0, ["5"] = 0x4040FF } local blist = {} for entry in (vmip.BUILDINGS or ""):gmatch("[^,]+") do local name, tier = entry:match("^(.-):(%d+)$") if name then name = name:gsub("_", " "):gsub("(%a)([%w]*)", function(a, b) return a:upper() .. b end) blist[#blist + 1] = { text = name .. " T" .. tier, col = TIERCOL[tier] or C.text } end end table.sort(blist, function(a, b) return a.text < b.text end) if #blist == 0 then txt(10, "none", C.dim); nl() else -- two columns, like the in-game display local rows = math.ceil(#blist / 2) for i = 1, rows do local a, b = blist[i], blist[i + rows] WindowText(WIN, "f", a and a.text or "", 10, ly, 0, 0, a and a.col or C.text) if b then WindowText(WIN, "f", b.text, 286, ly, 0, 0, b.col) end nl(13) end end local builds = split(vmip.BUILDS or "", ";") if #builds > 0 then nl(4) for i = 1, math.min(#builds, 3) do local f = split(builds[i], "|") -- under construction: name + time remaining only (resources omitted) local secs = num(f[5]) local rem = f[5] and (secs >= 3600 and string.format("%dh %dm left", math.floor(secs / 3600), math.floor((secs % 3600) / 60)) or (math.floor(secs / 60) .. "m left")) or "?" txt(10, string.format("constr: %-16s %s", f[1] or "?", rem), C.warn); nl() end end end
local function draw_city(my, vmip) header("-- Ships --") local ships = split(vmip.SHIPS or "", ";") if #ships == 0 then txt(10, "none", C.dim); nl() else -- two columns so all 10 ships fit without clipping the panels below local slist = {} for i = 1, math.min(#ships, 10) do local f = split(ships[i], "|") local eta = tonumber(f[5]) and (math.floor(num(f[5]) / 60) .. "m") or "" slist[i] = { text = string.format("%-12s %-10s %s", f[1] or "?", f[4] or "", eta), col = C.text, } end local rows = math.ceil(#slist / 2) for i = 1, rows do local a, b = slist[i], slist[i + rows] WindowText(WIN, "f", a and a.text or "", 10, ly, 0, 0, a and a.col or C.text) if b then WindowText(WIN, "f", b.text, 286, ly, 0, 0, b.col) end nl(13) end end nl(4) header("-- Carts --") local carts = split(vmip.CARTS or "", ";") if #carts == 0 then txt(10, "no carts out", C.dim); nl() else for i = 1, math.min(#carts, 4) do local f = split(carts[i], "|") local eta = f[4] and (math.floor(num(f[4]) / 60) .. "m") or "?" txt(10, string.format("%-4s %-10s -> %-16s %5s x%s", f[1] or "?", f[2] or "?", f[3] or "?", eta, f[5] or "?")); nl() end end nl(4) header("-- Refinery --") if (vmip.REFINERY or "") == "" then txt(10, "none", C.dim); nl() else -- name:tier:current:max:STAGES ('|' between refineries; STAGES = 'label,amount,pct' joined by ';') for ri, r in ipairs(split(vmip.REFINERY, "|")) do local f = split(r, ":") if f[1] and f[1] ~= "" then local name = f[1]:gsub("_", " "):gsub("(%a)([%w]*)", function(a, b) return a:upper() .. b:lower() end) local cur, max = num(f[3]), num(f[4]) -- aging stages: raw -> refined, each with an amount and a quality % local stages, tip = {}, {} for _, s in ipairs(split(f[5] or "", ";")) do local g = split(s, ",") if g[1] and g[1] ~= "" then stages[#stages + 1] = { amt = num(g[2]), pct = num(g[3]) } tip[#tip + 1] = string.format("%s %d (%d%%)", g[1], num(g[2]), num(g[3])) end end txt(10, string.format("%-16s T%s %3d/%-4d", name, f[2] or "?", cur, max), cur >= max and C.good or C.text) -- quality bar: full width = capacity; each stage a segment sized by amount, coloured by quality local bx1, bx2 = 220, 548 WindowRectOp(WIN, 2, bx1, ly + 1, bx2, ly + 11, C.panel) if max > 0 then local sx = bx1 for _, st in ipairs(stages) do local w = math.floor((bx2 - bx1) * st.amt / max) if w > 0 then WindowRectOp(WIN, 2, sx, ly + 2, math.min(sx + w, bx2 - 1), ly + 10, grad(st.pct)) sx = sx + w end end end WindowRectOp(WIN, 1, bx1, ly + 1, bx2, ly + 11, C.border) WindowAddHotspot(WIN, "refy_" .. ri, 10, ly, bx2, ly + 12, "", "", "", "", "", (#tip > 0 and table.concat(tip, " ") or "empty"), 0, 0) nl() end end txt(10, "bar = fill x quality (red raw -> green refined) hover a row for stages", C.dim); nl(11) end end
local function draw_production(my, vmip) header("-- Production / tick --") local prod = {} for pair in (vmip.PRODUCTION or ""):gmatch("[^,]+") do local r, a = pair:match("^(%a+):(%-?%d+)$") if r then prod[#prod + 1] = { r = r, a = tonumber(a) } end end if #prod == 0 then txt(10, "no data", C.dim); nl() else table.sort(prod, function(x, y) return x.r < y.r end) local rows = math.ceil(#prod / 2) local function pcell(e, x) if e then local name = e.r:gsub("^%l", string.upper) WindowText(WIN, "f", string.format("%-9s %s%d", name, e.a >= 0 and "+" or "", e.a), x, ly, 0, 0, e.a >= 0 and C.good or C.bad) end end for i = 1, rows do pcell(prod[i], 10); pcell(prod[i + rows], 200) nl(13) end end nl(4) header("-- Routes --") if (vmip.ROUTES or "") == "" then txt(10, "none", C.dim); nl() else local rlist = {} for _, r in ipairs(split(vmip.ROUTES, ";")) do local f = split(r, "|") if f[2] then local road = not (f[7] or "No"):find("No") local fort = not (f[8] or "No"):find("No") local col = (road and fort) and C.good or ((road or fort) and C.warn or C.dim) rlist[#rlist + 1] = { name = f[2]:sub(1, 12), col = col } end end table.sort(rlist, function(a, b) return a.name < b.name end) -- 3 columns so all towns fit once every route is established local xs = { 10, 190, 370 } local rows = math.ceil(#rlist / 3) for i = 1, rows do for c = 0, 2 do local e = rlist[i + c * rows] if e then WindowText(WIN, "f", e.name, xs[c + 1], ly, 0, 0, e.col) end end nl(13) end txt(10, "green = road + fort yellow = one grey = none", C.dim); nl(11) end nl(4) -- warehouse with freshness bars local wb = (vmip.BUILDINGS or "") .. "," local tier = wb:match("warehouse:(%d+),") or "1" local wmax = ({ ["1"]=400, ["2"]=1000, ["3"]=1750, ["4"]=3000, ["5"]=5250 })[tier] or 400 -- one row per good: total amount, avg-quality bar, stale batches noted local byg, tot = {}, 0 for _, e in ipairs(split(vmip.WSTOCK or "", ";")) do local f = split(e, "|") if f[1] and f[1] ~= "amber" then -- amber was replaced by sunstone; hide the last leftovers local amt, q = num(f[2]), tonumber(f[3]) or 100 local g = byg[f[1]] if not g then g = { amt = 0, qsum = 0, minq = 100, stale = 0 }; byg[f[1]] = g end g.amt = g.amt + amt g.qsum = g.qsum + q * amt if q < 100 then g.stale = g.stale + amt if q < g.minq then g.minq = q end end tot = tot + amt end end local stock = {} for good, g in pairs(byg) do stock[#stock + 1] = { good = good, g = g } end table.sort(stock, function(a, b) return a.good < b.good end) header(string.format("-- Warehouse %d / %d --", tot, wmax)) if #stock == 0 then txt(10, "empty", C.dim); nl() else for _, f in ipairs(stock) do local g = f.g local avgq = g.amt > 0 and math.floor(g.qsum / g.amt + 0.5) or 100 txt(10, string.format("%-10s %4d", f.good, g.amt)) WindowRectOp(WIN, 2, 150, ly + 1, 330, ly + 12, C.panel) local fill = math.floor(178 * math.min(avgq, 100) / 100) if fill > 0 then WindowRectOp(WIN, 2, 151, ly + 2, 151 + fill, ly + 11, grad(avgq)) end WindowRectOp(WIN, 1, 150, ly + 1, 330, ly + 12, C.border) if g.stale > 0 then txt(338, string.format("%d@%d%%", g.stale, g.minq), C.bad) else txt(338, "100%", C.dim) end nl(15) end end end
local function draw_people(my, vmip) header("-- Forces --") txt(10, string.format("Thralls %s Followers %s", vmip.THRALLS or "?", (vmip.THRALL_FOLLOWER or "?"):sub(1, 30))); nl() txt(10, string.format("Garrison %s Threk %s", vmip.GARRISON or "?", vmip.MTHREK or "?")); nl() nl(4) header("-- Hird Guard --") local hird = split(vmip.HIRD or "", ";") if #hird == 0 then txt(10, "no hird", C.dim); nl() else for i = 1, math.min(#hird, 10) do local f = split(hird[i], "|") txt(10, string.format("%-16s %s/%s/%s/%s %s %s", f[2] or "?", f[4] or "?", f[5] or "?", f[6] or "?", f[7] or "?", f[9] or "?", f[10] or "?")); nl() end end nl(4) header("-- Staff --") local staff = split(vmip.STAFF or "", ";") if #staff == 0 then txt(10, "no staff hired", C.dim); nl() else txt(10, string.format("%-16s %-13s %-4s%-4s%-4s%-4s%-4s%-4s%-4s", "", "", "Cbt", "Trd", "Cft", "Sea", "Wld", "Lnd", "Chm"), C.dim); nl(13) for i = 1, math.min(#staff, 10) do local f = split(staff[i], "|") local s = split(f[4] or "", ",") txt(10, string.format("%-16s %-13s %-4s%-4s%-4s%-4s%-4s%-4s%-4s", f[1] or "?", f[2] or "?", s[1] or "?", s[2] or "?", s[3] or "?", s[4] or "?", s[5] or "?", s[6] or "?", s[7] or "?")); nl(13) end end nl(4) header("-- Bonds --") local bonds = split(vmip.BONDS or "", ";") if #bonds == 0 then txt(10, "no bonds", C.dim); nl() else -- member number -> short (first) name from HIRD; the truncated feed may not -- name members 4+, which then show as #n local name = {} for _, h in ipairs(split(vmip.HIRD or "", ";")) do local f = split(h, "|") if f[1] and f[2] then name[f[1]] = (f[2]:match("^(%S+)") or f[2]) end end -- matrix[a][b] = 4th field of the bond; collect the member ids present local m, ids, seen = {}, {}, {} for _, b in ipairs(bonds) do local f = split(b, "|") local a, c, val = f[1], f[2], f[4] or "?" if a and c then m[a] = m[a] or {}; m[a][c] = val m[c] = m[c] or {}; m[c][a] = val if not seen[a] then seen[a] = true; ids[#ids + 1] = a end if not seen[c] then seen[c] = true; ids[#ids + 1] = c end end end table.sort(ids, function(x, y) return (tonumber(x) or 0) < (tonumber(y) or 0) end) local hdr = string.rep(" ", 11) for _, c in ipairs(ids) do hdr = hdr .. string.format("%-4s", c) end txt(10, hdr, C.dim); nl() for _, a in ipairs(ids) do local row = string.format("%-2s%-9s", a, (name[a] or ("#" .. a)):sub(1, 8)) for _, c in ipairs(ids) do if a == c then row = row .. string.format("%-4s", "-") else row = row .. string.format("%-4s", (m[a] and m[a][c]) or ".") end end txt(10, row, C.text); nl() end end end
local function draw_holds(my, vmip) header("-- Holds: standing & reputation --") local vrep = parse_idx_table(vmip.VREP) local stand = parse_idx_table(vmip.STANDINGS) WindowText(WIN, "f", string.format("%-16s %-10s %6s %6s", "Hold", "Standing", "Bond", "Rep"), 10, ly, 0, 0, C.dim); nl() for i = 0, 20 do local v, s = vrep[i], stand[i] if v or s then local name = HOLDCITY[i] or (v and v[2]) or (s and s[2]) or ("?" .. i) local standing = (s and s[4]) or "-" -- standing -> colour (add tiers here as they're unlocked) local scol = (standing == "Allied" and 0x40FF40) -- brighter green (above Friendly) or (standing == "Friendly" and C.good) -- green or (standing == "Hostile" and C.bad) -- red or C.label -- default (Neutral, etc.) WindowText(WIN, "f", string.format("%-16s", name:sub(1, 16)), 10, ly, 0, 0, C.text) WindowText(WIN, "f", string.format("%-10s", standing), 129, ly, 0, 0, scol) WindowText(WIN, "f", string.format("%6s %6s", (s and s[3]) or "-", (v and v[3]) or "-"), 204, ly, 0, 0, C.label) nl(13) end end nl(8) header("-- War status --") local blot = split(vmip.BLOT or "", "|") txt(10, string.format("Blot %s pool %s (%s/%s)", blot[1] or "?", blot[2] or "?", blot[3] or "?", blot[4] or "?")); nl() local raid = split(vmip.RAID or "", "|") txt(10, string.format("Raid %s %s %s Garrison %s", raid[1] or "?", raid[2] or "", raid[3] or "", vmip.GARRISON or "?")); nl() txt(10, string.format("Monuments %s Varangians %s", vmip.MONUMENTS or "?", (vmip.VARANG == "^" or vmip.VARANG == "") and "none" or (vmip.VARANG or "?"))); nl() end
-- voyage chart char -> colour (BGR) local SEACHART = { ["#"] = 0x303030, -- unrevealed ["O"] = 0xD0A000, ["~"] = 0xD0A000, -- open sea ["F"] = 0x909090, -- fog ["?"] = 0x505050, -- unknown ["I"] = 0x20C0C0, -- island ["H"] = 0x40C040, -- harbor ["W"] = 0x4040E0, -- wreck ["T"] = 0x5050F0, -- storm ["X"] = 0xE060E0, -- objective ["S"] = 0xFFFFFF, -- your ship ["+"] = 0x60E060, [">"] = 0x60E0E0, -- queued path / destination ["="] = 0xD06000, -- crosscurrent ["^"] = 0x406060, -- deadwater ["B"] = 0x8040C0, -- stormbelt ["*"] = 0x308040, -- resolved node (yellow * = resolved harbor) [" "] = 0x202830, -- sea } local SEALETTER = { S = true, X = true, H = true, W = true, T = true, I = true, [">"] = true, ["*"] = true, B = true }
-- log any newly-seen unmapped chart characters to a file (once each), instead of -- cluttering the Sea window. File lives next to the plugin: vik_unmapped.log local logged_chart_chars = {} local function log_unmapped(unknown) local new = {} for c in pairs(unknown) do if not logged_chart_chars[c] then logged_chart_chars[c] = true; new[#new + 1] = c end end if #new == 0 then return end table.sort(new) local f = io.open(GetPluginInfo(GetPluginID(), 20) .. "vik_unmapped.log", "a") if not f then return end f:write(os.date("%Y-%m-%d %H:%M:%S") .. " unmapped chart chars: " .. table.concat(new, " ") .. "\n") f:close() end
local function draw_sea(my, vmip) local v = split(vmip.VOYAGE or "", "|") txt(10, "Auto-nav: " .. (sea_nav.on and "ON" or "off") .. ((sea_nav.on and sea_nav.target) and (" -> " .. sea_nav.target.coord) or "") .. ((sea_nav.on and sea_nav.original) and (" (resume " .. sea_nav.original .. ")") or "") .. " resolve: " .. (sea_nav.resolve == "" and "manual" or sea_nav.resolve) .. " (vnav on|off | vnav resolve <opt>)", sea_nav.on and C.good or C.dim); nl(15) if #v < 10 then header("-- Sea --") txt(10, "No voyage under way.", C.dim); nl() local ships = split(vmip.SHIPS or "", ";") if #ships > 0 and ships[1] ~= "" then nl(4) header("-- Fleet --") if (vmip.SHPLOTS or "") ~= "" then txt(10, "Ship plots: " .. (vmip.SHPLOTS or ""):gsub("|", " / "), C.dim); nl() end -- SHIPS holds the whole fleet (name | ? | status | dest | ...) for i = 1, math.min(#ships, 10) do local f = split(ships[i], "|") txt(10, string.format("%-13s %-9s %s", f[1] or "?", f[3] or "?", f[4] or "")); nl() end end return end header(string.format("-- Voyage: %s - %s (%s) --", v[3] or "?", v[4] or "?", v[5] or "?")) -- left column: text facts / right column: condition bars local top = ly -- VOYAGE fields: 6=danger, 7=x, 8=y (0-based chart cell), 17=steps, 18=next_move (seconds) local vpx, vpy = num(v[7]), num(v[8]) local pos = string.char(65 + vpy) .. string.format("%02d", vpx + 1) -- next_move only refreshes when the feed does, so count down locally. Re-anchor whenever the -- value changes OR a move happens (steps++), since the server resets next_move at each move -- -- otherwise a first read taken mid-interval leaves the countdown reading high. local nm, nsteps = num(v[18]), num(v[17]) if nm ~= sea_nav.nm_val or nsteps ~= sea_nav.nm_steps then sea_nav.nm_val, sea_nav.nm_at, sea_nav.nm_steps = nm, os.time(), nsteps end local left = math.max(0, (sea_nav.nm_val or 0) - (os.time() - (sea_nav.nm_at or os.time()))) local nxt = (left > 0) and (math.ceil(left / 60) .. "m") or "moving" txt(10, string.format("State: %-9s Next square: %s", v[1] or "?", nxt)); nl() txt(10, string.format("Position: %-9s Steps: %s", pos, v[17] or "?")); nl() txt(10, string.format("Threat: %s [%s]", v[19] or "-", v[20] or "?")); nl() txt(10, string.format("Pressure: %s Danger: %s", v[21] or "?", v[6] or "?")); nl() txt(10, string.format("Captain: %s", v[25] or "?")); nl() txt(10, string.format("Identity: %s", v[26] or "?")); nl() txt(10, ("Traits: " .. (v[27] or "") .. ", " .. (v[28] or "")):sub(1, 40), C.dim); nl() local bottom = ly ly = top local function seabar(label, val, invert) local n = num(val) local pct = invert and (100 - n) or n WindowText(WIN, "f", label, 300, ly, 0, 0, C.label) WindowRectOp(WIN, 2, 366, ly + 1, 496, ly + 12, C.panel) local fill = math.floor(128 * math.min(math.max(pct, 0), 100) / 100) if fill > 0 then WindowRectOp(WIN, 2, 367, ly + 2, 367 + fill, ly + 11, grad(pct)) end WindowRectOp(WIN, 1, 366, ly + 1, 496, ly + 12, C.border) WindowText(WIN, "f", n .. "%", 502, ly + 1, 0, 0, C.text) nl() end seabar("Hull", v[11]) seabar("Morale", v[12]) seabar("Supplies", v[13]) seabar("Stress", v[14], true) WindowText(WIN, "f", string.format("Crew %s/%s", v[15] or "?", v[16] or "?"), 300, ly, 0, 0, C.text); nl() local wx = split(vmip.WEATHER or "", "|") WindowText(WIN, "f", string.format("Weather: %s/%s", wx[1] or "?", wx[2] or "?"), 300, ly, 0, 0, C.dim); nl() ly = math.max(ly, bottom) + 4 -- chart local ch = split(vmip.VCHH or "", "|") local cw, chh = num(ch[1]), num(ch[2]) if cw > 0 then header(string.format("-- Chart %dx%d (%s) --", cw, chh, ch[3] or "?")) local bs = math.max(8, math.min(16, math.floor(380 / math.max(cw, 1)))) local x0, y0 = 30, ly + 14 -- room for A-P (left) and 01-16 (top) axis labels local unknown = {} -- X-axis: column numbers across the top for col = 1, cw do WindowText(WIN, "f", string.format("%02d", col), x0 + (col - 1) * bs + math.floor(bs / 2) - 6, y0 - 12, 0, 0, C.label) end for row = 0, chh - 1 do -- Y-axis: row letter down the left (A, B, C, ...) WindowText(WIN, "fb", string.char(65 + row), x0 - 13, y0 + row * bs + math.floor(bs / 2) - 6, 0, 0, C.label) local rowstr = vmip[string.format("VCR%02d", row)] if rowstr then for col = 1, math.min(#rowstr, cw) do local c = rowstr:sub(col, col) local colr = SEACHART[c] if not colr then colr = 0x404040; unknown[c] = true end WindowRectOp(WIN, 2, x0 + (col - 1) * bs, y0 + row * bs, x0 + col * bs - 1, y0 + (row + 1) * bs - 1, colr) if SEALETTER[c] then WindowText(WIN, "fb", c, x0 + (col - 1) * bs + math.floor(bs / 2) - 4, y0 + row * bs + math.floor(bs / 2) - 7, 0, 0, c == "S" and 0x000000 or 0xFFFFFF) end -- click a cell to queue a voyage to that coordinate (e.g. C05) local coord = string.char(65 + row) .. string.format("%02d", col) WindowAddHotspot(WIN, "vq_" .. coord, x0 + (col - 1) * bs, y0 + row * bs, x0 + col * bs - 1, y0 + (row + 1) * bs - 1, "", "", "vik_voyage_click", "", "", "click: vvoyage queue " .. coord, 1, 0) end end end WindowRectOp(WIN, 1, x0 - 1, y0 - 1, x0 + cw * bs + 1, y0 + chh * bs + 1, C.border) -- legend beside the chart local lx = x0 + cw * bs + 14 local lyy = y0 for _, lg in ipairs({ {"S ship",0xFFFFFF}, {"X objective",0xE060E0}, {"H harbor",0x40C040}, {"W wreck",0x4040E0}, {"T storm",0x5050F0}, {"I island",0x20C0C0}, {"F fog",0x909090}, {"# unrevealed",0x303030}, {"O open sea",0xD0A000}, {"* resolved",0x308040}, {"B stormbelt",0x8040C0} }) do WindowRectOp(WIN, 2, lx, lyy + 2, lx + 8, lyy + 10, lg[2]) WindowText(WIN, "f", lg[1], lx + 12, lyy, 0, 0, C.dim) lyy = lyy + 14 end -- clear the voyage queue WindowRectOp(WIN, 2, lx, lyy + 6, lx + 70, lyy + 22, C.panel) WindowRectOp(WIN, 1, lx, lyy + 6, lx + 70, lyy + 22, C.border) WindowText(WIN, "fb", "Clear", lx + 20, lyy + 9, 0, 0, C.head) WindowAddHotspot(WIN, "vq_clear", lx, lyy + 6, lx + 70, lyy + 22, "", "", "vik_voyage_click", "", "", "Send: vvoyage clear", 1, 0) -- resolve buttons: actions come from VRESOLVE and vary per encounter -- (extra gap below Clear so it's not mis-tapped on mobile) local ry = lyy + 47 local resolves = {} for a in (vmip.VRESOLVE or ""):gmatch("[^,]+") do local t = a:gsub("^%s+", ""):gsub("%s+$", "") if t ~= "" then resolves[#resolves + 1] = t end end if #resolves == 0 then WindowText(WIN, "f", "(no resolve pending)", lx, ry + 2, 0, 0, C.dim) else for _, act in ipairs(resolves) do local label = act:sub(1, 1):upper() .. act:sub(2) WindowRectOp(WIN, 2, lx, ry, lx + 70, ry + 16, C.panel) WindowRectOp(WIN, 1, lx, ry, lx + 70, ry + 16, C.border) WindowText(WIN, "fb", label, lx + 35 - #label * 4, ry + 2, 0, 0, C.head) WindowAddHotspot(WIN, "vr_" .. act:lower(), lx, ry, lx + 70, ry + 16, "", "", "vik_voyage_click", "", "", "Send: vvoyage resolve " .. act:lower(), 1, 0) ry = ry + 19 end end ly = y0 + chh * bs + 6 log_unmapped(unknown) end -- saga local saga = split(vmip.VSAGA or "", ";") if #saga > 0 then header("-- Saga --") for i = math.max(1, #saga - 2), #saga do if ly > H - 16 then break end txt(10, saga[i]:sub(1, 74), C.dim); nl(13) end end end
local function draw_voyage(my, vmip) -- comma-separated "name status" list (VBOONS-style) local function listsec(title, field) header(title) local v = vmip[field] or "" if v == "" then txt(10, "none", C.dim); nl() else for item in v:gmatch("[^,]+") do txt(10, (item:gsub("^%s+", ""):gsub("%s+$", "")):sub(1, 60)); nl() end end end -- comma-separated "name:count" list (VAIDS / VGOODS-style) local function countsec(title, field) header(title) local v = vmip[field] or "" if v == "" then txt(10, "none", C.dim); nl() else for item in v:gmatch("[^,]+") do item = item:gsub("^%s+", ""):gsub("%s+$", "") local name, n = item:match("^(.-):(%-?%d+)$") if name then name = (name:gsub("_", " "):gsub("(%a)([%w]*)", function(a, b) return a:upper() .. b end)) txt(10, string.format("%-30s %s", name:sub(1, 30), n)); nl() else txt(10, item:sub(1, 60)); nl() end end end end listsec("-- Boons --", "VBOONS") nl(4) countsec("-- Aids --", "VAIDS") nl(4) countsec("-- Goods --", "VGOODS") nl(4) countsec("-- Curios --", "VCURIOS") end
local function draw_map(my, vmip) local hd = split(vmip.VMAPH or "", "|") local mw, mh, px, py = num(hd[1]), num(hd[2]), num(hd[3]), num(hd[4]) if mw == 0 then txt(10, "(no map feed - run vmapon)", C.dim); nl() return end header(string.format("-- Territory %dx%d @ %d,%d --", mw, mh, px, py)) -- legend local legend = { {"Tund",0x606060},{"Hill",0x20C0C0},{"Mtn",0x3030D0},{"Frst",0x208020}, {"Plns",0x60C060},{"Watr",0xD0A000},{"Road",0x181818},{"Gate",0x909090}, {"Lin",0x2080E0},{"Set",0x40C0E0},{"You",0xFFFFFF} } local lx = 10 for _, lg in ipairs(legend) do WindowRectOp(WIN, 2, lx, ly + 2, lx + 8, ly + 10, lg[2]) WindowText(WIN, "f", lg[1], lx + 10, ly, 0, 0, C.dim) lx = lx + 10 + #lg[1] * 7 + 7 end nl(16) local bs = math.max(4, math.min(10, math.floor(520 / math.max(mw, 1)))) local x0, y0 = 14, ly + 2 local unknown = {} local POI_LABEL = { L = "Lin", S = "Set", C = "Cap", ["*"] = "POI", R = "Ruin", M = "Cap" } local pois = {} for row = 0, mh - 1 do local rowstr = vmip[string.format("VMR%02d", row)] local mask = vmip[string.format("MEE%02d", row)] if rowstr then for col = 1, math.min(#rowstr, mw) do local ch = rowstr:sub(col, col) local colr = TERRAIN[ch] if not colr then colr = 0x282828; unknown[ch] = true end if mask and mask:sub(col, col) == "0" then colr = 0x000000 end WindowRectOp(WIN, 2, x0 + (col - 1) * bs, y0 + row * bs, x0 + col * bs, y0 + (row + 1) * bs, colr) if POI_LABEL[ch] then pois[#pois + 1] = { x = col - 1, y = row, ch = ch } end end end end -- hover a town for its type, name and coordinates local locs = parse_locs(vmip.VMAPL) local feednames = {} for _, lc in ipairs(locs) do feednames[lc.x .. "|" .. lc.y] = lc.name end for _, p in ipairs(pois) do local key = p.x .. "|" .. p.y local label = (POI_LABEL[p.ch] or "?") .. " (" .. p.x .. "," .. p.y .. ")" local nm = locname(p.x, p.y) or feednames[key] if nm then label = nm .. " - " .. label end WindowAddHotspot(WIN, "poi_" .. key, x0 + p.x * bs, y0 + p.y * bs, x0 + (p.x + 1) * bs, y0 + (p.y + 1) * bs, "", "", "", "", "", label, 0, 0) end -- location markers for _, lc in ipairs(locs) do if lc.x >= 0 and lc.x < mw and lc.y >= 0 and lc.y < mh then WindowRectOp(WIN, 1, x0 + lc.x * bs - 1, y0 + lc.y * bs - 1, x0 + (lc.x + 1) * bs + 1, y0 + (lc.y + 1) * bs + 1, loc_color(lc.type)) end end -- live player marker disabled (real-time redraws lagged the client); position is in the header coords WindowRectOp(WIN, 1, x0 - 1, y0 - 1, x0 + mw * bs + 1, y0 + mh * bs + 1, C.border) ly = y0 + mh * bs + 6 -- merged list: feed-named locations + towns scanned from the grid local merged, seen = {}, {} for _, lc in ipairs(locs) do seen[lc.x .. "|" .. lc.y] = true lc.name = locname(lc.x, lc.y) or lc.name merged[#merged + 1] = lc end for _, p in ipairs(pois) do local key = p.x .. "|" .. p.y if not seen[key] then seen[key] = true merged[#merged + 1] = { type = POI_LABEL[p.ch], name = locname(p.x, p.y), x = p.x, y = p.y } end end -- known locations always listed, even with no marker on the map local known = {} for key in pairs(TRAVEL_CODE) do known[key] = true end for key in pairs(DEFAULT_LOCNAMES) do known[key] = true end for key in pairs(known) do if not seen[key] then local x, y = key:match("^(%-?%d+)|(%-?%d+)$") local typ if TRAVEL_CODE[key] then typ = (key == "35|17") and "Cap" or "Lin" else typ = DEFAULT_LOCTYPE[key] or "POI" end merged[#merged + 1] = { type = typ, name = locname(tonumber(x), tonumber(y)), x = tonumber(x), y = tonumber(y) } end end if #merged > 0 then local function rank(e) if travel_code(e.x .. "|" .. e.y) then return 1 end if e.name then return 2 end return 3 end table.sort(merged, function(a, b) local ra, rb = rank(a), rank(b) if ra ~= rb then return ra < rb end if a.name and b.name then return a.name < b.name end if a.y ~= b.y then return a.y < b.y end return a.x < b.x end) header("-- Locations (click a town to walk there) --") local colx, coltop = 10, ly local maxly = ly for _, lc in ipairs(merged) do if ly > H - 29 then if colx == 10 then maxly = math.max(maxly, ly) colx = 286; ly = coltop else break end end local t = (lc.type or "?"):gsub("_.*$", "") t = t:sub(1, 1):upper() .. t:sub(2) local key2 = lc.x .. "|" .. lc.y local clickable = travel_code(key2) ~= nil WindowText(WIN, "f", t, colx, ly, 0, 0, loc_color(lc.type)) WindowText(WIN, "f", string.format("%-14s (%d,%d)", (lc.name or "-"):sub(1, 14), lc.x, lc.y), colx + 50, ly, 0, 0, clickable and 0x40E0E0 or (lc.name and C.label or C.dim)) if clickable then WindowAddHotspot(WIN, "trav_" .. key2, colx, ly, colx + 264, ly + 12, "", "", "vik_travel_click", "", "", "Click: walk to " .. (lc.name or "here") .. " Right-click: I am here", 1, 0) end nl(13) end ly = math.max(maxly, ly) end local u = {} for ch in pairs(unknown) do u[#u + 1] = ch end if #u > 0 then table.sort(u) txt(10, "unmapped terrain chars: " .. table.concat(u, " ") .. " (tell Claude)", C.dim); nl(13) end end
-- City Plan tab: 12x12 placement grid (inner CPT rows 4-15, cols 5-16), coloured by terrain / -- role, with a clickable building palette. Pick a building, then click a cell to place it. local function draw_plan(my, vmip) local rows = {} for i = 0, 19 do rows[i] = vmip["CPT" .. string.format("%02d", i)] end local plan = split(vmip.CPLAN or "", "|") cp_accumulate(vmip.CPB) -- catch a placement even if we only see it here local placed = tonumber(plan[3]) or 0 -- CPLAN field 3 = total buildings placed local allowed = plan[4] or "?"
-- placements are accumulated in cp_placed (the feed only sends the latest). Expand each -- building's w x h footprint into pmap["row,col"] = { letter, name }; terrain stays in CPT. local pmap, pcount = {}, {} for _, b in pairs(cp_placed) do pcount[b.letter] = (pcount[b.letter] or 0) + 1 for dr = 0, b.h - 1 do for dc = 0, b.w - 1 do pmap[(b.row + dr) .. "," .. (b.col + dc)] = { letter = b.letter, name = b.name } end end end local tracked = cp_count()
local hdr = string.format("Placed %d / %s", placed, allowed) header("-- City Plan --") txt(10, hdr, C.text) local note = (tracked < placed) and string.format("(%d tracked - others appear as you place them; 'vplan clear' to reset)", tracked) or "(grows with rank)" txt(10 + WindowTextWidth(WIN, "f", hdr) + 6, note, (tracked < placed) and C.warn or C.dim) -- view-style toggle (top right): cycle text -> tiles -> icons local tlbl = "view: " .. plan_style local tx = W - WindowTextWidth(WIN, "f", tlbl) - 12 txt(tx, tlbl, C.head) WindowAddHotspot(WIN, "plan_style", tx, ly, tx + WindowTextWidth(WIN, "f", tlbl), ly + 12, "", "", "vik_plan_style", "", "", "Switch text / tiles view", 1, 0) nl(15)
if not rows[4] then txt(10, "no city-plan feed yet - enable it in-game / vtoggle mip_city", C.dim); nl() return end
-- selection line + Clear control if plan_sel then local b = PLAN_BY_L[plan_sel] local s = "Selected: " .. plan_sel .. " " .. (b and b.name or "?") txt(10, s, b and PLAN_ROLE[b.role] or C.text) local cx = 10 + WindowTextWidth(WIN, "f", s) + 10 txt(cx, "[Clear]", C.warn) WindowAddHotspot(WIN, "plan_clear", cx, ly, cx + WindowTextWidth(WIN, "f", "[Clear]"), ly + 12, "", "", "vik_plan_clear", "", "", "Clear selection", 1, 0); nl(15) else txt(10, "Pick a building below, then click a grid cell to place it.", C.dim); nl(15) end
-- grid: text = single glyphs (classic), tiles = filled cells, icons = pixel-art sprites local icons = (plan_style == "icons") local img_ok = icons and cp_load_image() local tiles = (plan_style == "tiles") or icons -- icons reuse the filled-tile layout local gx0 = 34 local cw = icons and 22 or (tiles and 17 or 14) local chh = icons and 22 or (tiles and 16 or 13) for c = 1, 12 do WindowText(WIN, "f", tostring(c % 10), gx0 + (c - 1) * cw + math.floor(cw / 2) - 3, ly, 0, 0, C.dim) end local gy = ly + 12 if tiles then WindowRectOp(WIN, 1, gx0 - 1, gy - 1, gx0 + 12 * cw + 1, gy + 12 * chh + 1, C.border) end for r = 0, 11 do local rowstr = rows[r + 4] or "" local rl = string.char(65 + r) WindowText(WIN, "f", rl, 18, gy + (tiles and 3 or 0), 0, 0, C.label) for c = 0, 11 do local ch = rowstr:sub(5 + c, 5 + c) local ter = PLAN_TERRAIN[ch] local cx = gx0 + c * cw local bld = pmap[r .. "," .. c] -- a placed building here? local letter = bld and bld.letter local bcol = letter and ((PLAN_BY_L[letter] and PLAN_ROLE[PLAN_BY_L[letter].role]) or 0xF0F0F0) if tiles then local fill, glyphcol if letter then fill, glyphcol = 0x585048, bcol -- building tile elseif ter then fill, glyphcol = ter[3], ter[2] -- terrain tile else fill, glyphcol = 0x484848, 0xF0F0F0 end WindowRectOp(WIN, 2, cx + 1, gy + 1, cx + cw - 1, gy + chh - 1, fill) WindowRectOp(WIN, 1, cx, gy, cx + cw, gy + chh, 0x282828) if letter then local bi = PLAN_BY_L[letter] and PLAN_BY_L[letter].idx if img_ok and bi then -- blit the pixel-art sprite (its transparent bg lets the tile show) local sx = (bi % PLAN_ICON_COLS) * 22 local sy = math.floor(bi / PLAN_ICON_COLS) * 22 WindowDrawImageAlpha(WIN, "cityicons", cx, gy, cx + cw, gy + chh, 1.0, sx, sy) else local w = WindowTextWidth(WIN, "fb", letter) WindowText(WIN, "fb", letter, cx + math.floor((cw - w) / 2), gy + 2, 0, 0, glyphcol) end end else if letter then WindowText(WIN, "fb", letter, cx + 4, gy, 0, 0, bcol) else local col = ter and ter[2] or 0xF0F0F0 local gc = ch if ch == "H" then gc = "^" elseif ch == "w" then gc = "~" end WindowText(WIN, "f", gc, cx + 4, gy, 0, 0, col) end end local cell = rl .. tostring(c + 1) WindowAddHotspot(WIN, "plancell_" .. cell, cx, gy, cx + cw, gy + chh, "", "", "vik_plan_cell", "", "", "Cell " .. cell .. (bld and (": " .. bld.name) or (plan_sel and (" -> place " .. plan_sel) or " (pick a building first)")), 1, 0) end gy = gy + chh end ly = gy + 4 txt(10, tiles and "woods green hill blue-grey river blue plain dark buildings = role-coloured" or "plain . woods f hill ^ river ~", C.dim); nl(15)
-- building palette: 3 columns, click to select local cols, colw = 3, math.floor((W - 16) / 3) local perc = math.ceil(#PLAN_BLD / cols) local top = ly for i, b in ipairs(PLAN_BLD) do local ci = math.floor((i - 1) / perc) local ri = (i - 1) % perc local x = 8 + ci * colw local y = top + ri * 13 local sel = (plan_sel == b[1]) local n = pcount[b[1]] if n then WindowRectOp(WIN, 2, x, y + 3, x + 6, y + 9, 0x40E040) end -- green mark = placed local label = b[1] .. " " .. b[2] .. (n and n > 1 and (" x" .. n) or "") WindowText(WIN, sel and "fb" or "f", label, x + 9, y, 0, 0, PLAN_ROLE[b[3]] or C.text) WindowAddHotspot(WIN, "planpick_" .. i, x, y, x + colw - 4, y + 12, "", "", "vik_plan_pick", "", "", "Select " .. b[2] .. " (" .. b[1] .. ")" .. (n and (" - " .. n .. " placed") or ""), 1, 0) end ly = top + perc * 13 end
local function draw_feeds(my, vmip) header("-- Live feed keys (for building more tabs) --") local keys = {} for k in pairs(vmip) do if not k:match("^VMR%d") and not k:match("^MEE%d") and not k:match("^MES%d") and not k:match("^VCR%d") then keys[#keys + 1] = k end end table.sort(keys) local top, x = ly, 10 for _, k in ipairs(keys) do if ly > H - 16 then if x == 10 then x = 286; ly = top else txt(x, "...", C.dim) break end end local v = vmip[k] txt(x, string.format("%-13s %s", k:sub(1, 13), v:sub(1, 24)), #v > 0 and C.text or C.dim); nl(13) end end
-- wrapper so each mission/errand town gets a unique hotspot id while still -- delegating to the map's travel handler (id carries the x|y before the @uid). function vik_mtravel(flags, id) local coords = id:match("^mtrav_([%-%d|]+)@") if coords then vik_travel_click(flags, "trav_" .. coords) end end
-- click a mission number to send "vmission fulfill <number>" function vik_fulfill(flags, id) local num = id:match("^mfulfill_(%d+)$") if num then Send("vmission fulfill " .. num) end end
-- newbie errand buttons function vik_mnewbie(flags, id) if id == "mfetch" then Send("vmission newbie fetch") elseif id == "msubmit" then Send("vmission newbie submit") end end
-- click a voyage-chart cell to queue a destination (id = vq_<coord>, e.g. vq_C05) function vik_voyage_click(flags, id) if id == "vq_clear" then Send("vvoyage clear") return end local res = id:match("^vr_(.+)$") if res then Send("vvoyage resolve " .. res) return end local coord = id:match("^vq_(%a%d+)$") if coord then Send("vvoyage queue " .. coord) end end
-- patrol: commit a new patrol (number defaults to the last patrol's count) function vik_patrol_commit(flags, id) local _, vmip = getvars() local n = patrol_number(vmip) if n then Send("vpatrol commit " .. n) else Note("[viking] no patrol number known - use [change] to set one") end end
function vik_patrol_setnum(flags, id) local s = utils.inputbox("Hirdmadrs to commit (blank = use last patrol's count):", "Patrol commit number", GetVariable("patrol_num") or "") if not s then return end s = s:gsub("%D", "") SetVariable("patrol_num", s) -- "" clears the override -> back to default Note("[viking] patrol commit number: " .. (s ~= "" and s or "default (last patrol count)")) vik_draw() end
-- map a settlement name to its travel key (x|y), if it is travel-reachable -- normalise a town name for matching: lowercase, drop apostrophes/spaces/punctuation local function normtown(s) return ((s or ""):lower():gsub("[^%w]", "")) end local function town_travel_key(name) local target = normtown(name) for k, n in pairs(locnames) do if TRAVEL_CODE[k] and normtown(n) == target then return k end end for k, n in pairs(DEFAULT_LOCNAMES) do if TRAVEL_CODE[k] and normtown(n) == target then return k end end return nil end
-- draw a town name at (x, ly); if reachable, colour it cyan and overlay a -- click-to-travel hotspot (same routing as the Map tab) local function draw_town(x, name, uid) local key = town_travel_key(name) WindowText(WIN, "f", name, x, ly, 0, 0, key and C.head or C.text) if key then local w = WindowTextWidth(WIN, "f", name) WindowAddHotspot(WIN, "mtrav_" .. key .. "@" .. uid, x, ly, x + w, ly + 12, "", "", "vik_mtravel", "", "", "click to travel to " .. name, 1, 0) end end
local function draw_mission(my, vmip) header("-- Missions --") if (vmip.MISSIONS or "") == "" then txt(10, "no missions", C.dim); nl() else txt(10, "no", C.dim); txt(56, "town", C.dim); txt(160, "needs", C.dim); txt(330, "rep", C.dim); nl() for i, ms in ipairs(split(vmip.MISSIONS, ";")) do local f = split(ms, "|") -- id | desc | rep | ? | expiry | (empty) | town | goods(good:qty,...) local goods = (f[8] or ""):gsub(":", ""):gsub(",", " "):sub(1, 22) local mnum = f[1] or "?" WindowText(WIN, "f", mnum, 10, ly, 0, 0, C.good) WindowAddHotspot(WIN, "mfulfill_" .. mnum, 10, ly, 10 + WindowTextWidth(WIN, "f", mnum), ly + 12, "", "", "vik_fulfill", "", "", "click to fulfill mission " .. mnum, 1, 0) draw_town(56, f[7] or "?", "m" .. i) txt(160, goods) txt(330, f[3] or "?") nl() end end nl(6) header("-- Errand --") if (vmip.ERRAND or "") == "" then txt(10, "no errand", C.dim); nl() else local e = split(vmip.ERRAND, "|") -- id | desc | rep | timelimit(s) | from | to | good | qty txt(10, (e[2] or "?"):sub(1, 58)); nl() local fromn, ton = e[5] or "?", e[6] or "?" draw_town(10, fromn, "ef") local x2 = 10 + WindowTextWidth(WIN, "f", fromn) txt(x2, " -> ") local x3 = x2 + WindowTextWidth(WIN, "f", " -> ") draw_town(x3, ton, "et") local x4 = x3 + WindowTextWidth(WIN, "f", ton) local mins = tonumber(e[4]) and (math.floor(num(e[4]) / 60) .. "m") or "?" txt(x4, string.format(" %s x%s %s rep %s", e[7] or "?", e[8] or "?", e[3] or "?", mins)) nl() end -- newbie errand action buttons nl(4) local function mbtn(id, x1, label, tip) WindowRectOp(WIN, 2, x1, ly, x1 + 70, ly + 15, C.panel) WindowRectOp(WIN, 1, x1, ly, x1 + 70, ly + 15, C.border) WindowText(WIN, "fb", label, x1 + 35 - #label * 4, ly + 2, 0, 0, C.head) WindowAddHotspot(WIN, id, x1, ly, x1 + 70, ly + 15, "", "", "vik_mnewbie", "", "", tip, 1, 0) end mbtn("mfetch", 10, "Fetch", "Send: vmission newbie fetch") mbtn("msubmit", 90, "Submit", "Send: vmission newbie submit") nl(18) end
-- ---------------- main draw ---------------- function vik_draw() local my, vmip = getvars() -- track combat rounds: when RNDZ drops (combat ended / new fight reset its -- counter), the value just before the drop was the last fight's round count. local cur = tonumber(vmip.RNDZ) if cur then if prev_rndz and cur < prev_rndz then last_fight = prev_rndz SetVariable("last_fight", tostring(last_fight)) end prev_rndz = cur end if not visible then return end if not windowinfo then windowinfo = movewindow.install(WIN, 6, 0) end -- the icon-view city plan uses 22px tiles, so it needs a taller window than the default local winH = (tab == "Plan" and plan_style == "icons") and 624 or H WindowCreate(WIN, windowinfo.window_left, windowinfo.window_top, W, winH, windowinfo.window_mode, windowinfo.window_flags, C.bg) WindowFont(WIN, "f", "Lucida Console", 9, false, false, false, false) WindowFont(WIN, "fb", "Lucida Console", 9, true, false, false, false) WindowRectOp(WIN, 1, 0, 0, W, winH, C.border) -- title bar (drag) WindowRectOp(WIN, 2, 1, 1, W - 1, 18, C.title) WindowText(WIN, "fb", "Viking Status", math.floor(W / 2) - 45, 3, 0, 0, C.head) movewindow.add_drag_handler(WIN, 0, 0, W, 18, miniwin.cursor_hand) -- tabs local per = math.ceil(#TABS / 2) -- tabs across; two rows local tw = math.floor((W - 2) / per) for i, t in ipairs(TABS) do local r = math.floor((i - 1) / per) -- row 0 (top) or 1 (bottom) local c = (i - 1) % per local x1 = 1 + c * tw local y1 = 19 + r * 19 local y2 = y1 + 18 local sel = (t == tab) WindowRectOp(WIN, 2, x1, y1, x1 + tw - 1, y2, sel and C.tabsel or C.tabbg) WindowRectOp(WIN, 1, x1, y1, x1 + tw - 1, y2, C.border) WindowText(WIN, sel and "fb" or "f", t, x1 + math.floor(tw / 2) - #t * 4, y1 + 4, 0, 0, sel and C.head or C.label) WindowAddHotspot(WIN, "tab_" .. t, x1, y1, x1 + tw - 1, y2, "", "", "vik_tabclick", "", "", t, 1, 0) end ly = 63 if tab == "Stats" then draw_stats(my, vmip) elseif tab == "City" then draw_city(my, vmip) elseif tab == "Builds" then draw_builds(my, vmip) elseif tab == "Production" then draw_production(my, vmip) elseif tab == "People" then draw_people(my, vmip) elseif tab == "Settlers" then draw_settlers(my, vmip) elseif tab == "Holds" then draw_holds(my, vmip) elseif tab == "Sea" then draw_sea(my, vmip) elseif tab == "Voyage" then draw_voyage(my, vmip) elseif tab == "Map" then draw_map(my, vmip) elseif tab == "Plan" then draw_plan(my, vmip) elseif tab == "Mission" then draw_mission(my, vmip) elseif tab == "Feeds" then draw_feeds(my, vmip) end WindowShow(WIN, true) end
function vik_tabclick(flags, id) tab = id:sub(5) SetVariable("tab", tab) vik_draw() end
-- City Plan: pick a building from the palette, click a cell to place it function vik_plan_pick(flags, id) local idx = tonumber(id:match("^planpick_(%d+)$")) if idx and PLAN_BLD[idx] then plan_sel = PLAN_BLD[idx][1]; vik_draw() end end function vik_plan_clear() plan_sel = nil; vik_draw() end function vik_plan_reset() -- forget tracked placements (they'll re-learn as you place) cp_placed = {}; cp_save() ColourNote("cyan", "", "[plan] tracked placements cleared") vik_draw() end function vik_plan_style() plan_style = (plan_style == "text") and "tiles" or (plan_style == "tiles") and "icons" or "text" SetVariable("plan_style", plan_style) vik_draw() end function vik_plan_cell(flags, id) local cell = id:match("^plancell_(%w+)$") if not cell then return end if not plan_sel then Note("[plan] pick a building first, then click a cell"); return end Send("vplan place " .. plan_sel .. " " .. cell) Note("[plan] vplan place " .. plan_sel .. " " .. cell) end
function vik_settab(name) name = name:sub(1, 1):upper() .. name:sub(2):lower() for _, t in ipairs(TABS) do if t == name then tab = t; SetVariable("tab", tab); vik_draw(); return end end Note("[viking] no tab '" .. name .. "' (Stats City People Map Feeds)") end
function vik_dump() local dir = GetPluginInfo(GetPluginID(), 20) local path = dir .. "vmip_dump.txt" local f = io.open(path, "w") if not f then Note("[viking] could not write " .. path) return end local my, vmip = getvars() local keys = {} for k in pairs(vmip) do keys[#keys + 1] = k end table.sort(keys) f:write("vmip dump " .. os.date() .. "\n") for _, k in ipairs(keys) do f:write(k .. " = " .. vmip[k] .. "\n") end f:close() Note("[viking] full feed written to " .. path) end
function vik_toggle() visible = not visible SetVariable("visible", visible and "1" or "0") if visible then vik_draw() else WindowShow(WIN, false) end Note("[viking] window " .. (visible and "shown" or "hidden")) end
-- one pass of the auto sea-nav, called on every feed update function sea_nav_tick() if not sea_nav.on then return end if not IsConnected() then return end local _, vmip = getvars() local vy = split(vmip.VOYAGE or "", "|") if #vy < 10 then -- no active voyage sea_nav.had_voyage = false -- the next one starts on a fresh chart return end -- Every voyage gets a brand-new chart, so toured coords never carry over. Reset when the -- voyage name changes AND whenever a voyage starts (names can repeat between voyages). local vid = vy[4] or "" if vid ~= sea_nav.voyage or not sea_nav.had_voyage then sea_nav.voyage = vid; sea_nav.visited = {}; sea_nav.target = nil; sea_nav.original = nil end sea_nav.had_voyage = true local feats, ship = sea_chart_scan(vmip) if not ship then return end -- can't locate our ship on the chart yet
local has_node = (vmip.VRESOLVE or "") ~= ""
-- auto-resolve the current node per preference; returns true if it held/handled the node. -- Options moved from VRESOLVE (now just the node TYPE, e.g. "prompt_shadow") to VOFFERS -- (e.g. "hunt,evade"); read VOFFERS first and fall back to VRESOLVE for older feeds. local function try_resolve() if not has_node then return end if sea_nav.resolve == "" or sea_nav.resolve == "off" then return end -- manual: hold if (os.time() - (sea_nav.last_cmd_at or 0)) < 3 then return end local optsrc = ((vmip.VOFFERS or "") ~= "") and vmip.VOFFERS or vmip.VRESOLVE local opts = split(optsrc or "", ",") local offered = {} for _, o in ipairs(opts) do offered[o:gsub("%s", "")] = true end -- voyage metrics a preference entry can test, e.g. "resupply?supplies<50" local vy2 = split(vmip.VOYAGE or "", "|") local metric = { hull = num(vy2[11]), morale = num(vy2[12]), supplies = num(vy2[13]), stress = num(vy2[14]) } local function cond_ok(c) if not c or c == "" then return true end local m, op, n = c:match("^(%a+)([<>]=?)(%d+)$") if not m then return true end local val = metric[m:lower()]; if not val then return true end n = tonumber(n) if op == "<" then return val < n elseif op == ">" then return val > n elseif op == "<=" then return val <= n elseif op == ">=" then return val >= n end return true end local pick if sea_nav.resolve == "first" then pick = opts[1] and opts[1]:gsub("%s", "") else for entry in sea_nav.resolve:gmatch("[^,]+") do local kw, cond = entry:match("^%s*([^?%s]+)%s*%??%s*(.-)%s*$") if kw and offered[kw] and cond_ok(cond) then pick = kw; break end end -- no match -> hold for manual (safer than guessing) end if pick and pick ~= "" then sea_nav.last_cmd_at = os.time() Send("vvoyage resolve " .. pick) ColourNote("cyan", "", "[sea-nav] auto-resolving node with '" .. pick .. "'") end end
-- == ACTIVE TARGET: hold course until we actually arrive == -- The chart draws our queued course over the map (path '+', destination '>'), so once we -- queue an island its '>' marker HIDES the 'I' from the scan. If we re-scanned every tick we -- would see "no features", resume the original course (clearing the marker), the island would -- reappear, and we'd divert again -- an endless island<->course ping-pong. So while a target is -- set we do NOT re-scan or resume; we just wait for arrival (position or the queue emptying). if sea_nav.target then local t = sea_nav.target local dest = vqpath_dest(vmip.VQPATH) if dest == t.coord then sea_nav.enroute = true end -- confirmed our course leads there local onit = (ship.r == t.r and ship.c == t.c) local adj = (math.abs(ship.r - t.r) <= 1 and math.abs(ship.c - t.c) <= 1) -- arrived when we stand on it, OR a node popped while we're right next to it (islands/wrecks -- stop the ship adjacent), OR our confirmed course was consumed (queue emptied = we got there) local arrived = onit or (has_node and adj) or (sea_nav.enroute and dest == nil) if arrived then sea_nav.visited[t.coord] = true sea_nav.target = nil sea_nav.enroute = false -- fall through: resolve the node we just reached / pick the next feature else try_resolve() -- a mid-sail encounter can still pop while we sail; handle it, keep course return end end
-- == AT A NODE with no active target: resolve it (or hold for manual) == if has_node then try_resolve() return end
-- == FREE TO PICK: nearest unvisited feature == local best, bd for _, f in ipairs(feats) do if not sea_nav.visited[f.coord] then local d = (f.r - ship.r) ^ 2 + (f.c - ship.c) ^ 2 if not bd or d < bd then best, bd = f, d end end end if not best then -- nothing left to tour -- everything in sight is toured: resume the course we diverted from, if any if sea_nav.original and not sea_nav.visited[sea_nav.original] and (os.time() - (sea_nav.last_cmd_at or 0)) >= 2 then local orig = sea_nav.original sea_nav.original = nil sea_nav.last_cmd_at = os.time() Send("vvoyage clear") Send("vvoyage queue " .. orig) ColourNote("cyan", "", "[sea-nav] all features toured - resuming original course to " .. orig) end return end -- divert to the chosen feature (throttled). target is nil here, so this only fires once per pick. if (os.time() - (sea_nav.last_cmd_at or 0)) >= 2 then -- first time we take over: remember the course the player had queued, to resume later if not sea_nav.original then local od = vqpath_dest(vmip.VQPATH) if od and od ~= best.coord then sea_nav.original = od end end sea_nav.target = { coord = best.coord, r = best.r, c = best.c } sea_nav.enroute = false sea_nav.last_cmd_at = os.time() Send("vvoyage clear") Send("vvoyage queue " .. best.coord) ColourNote("cyan", "", "[sea-nav] course set to " .. best.sym .. " at " .. best.coord) end end
function sea_nav_set(s) sea_nav.on = (s == "on") SetVariable("seanav", sea_nav.on and "1" or "0") ColourNote("cyan", "", "[sea-nav] auto-navigation " .. (sea_nav.on and "ON" or "OFF")) if sea_nav.on then sea_nav_tick() end vik_draw() end
-- clear the toured list for the current voyage (re-consider every feature on the chart) function sea_nav_reset() sea_nav.visited = {}; sea_nav.target = nil; sea_nav.original = nil ColourNote("cyan", "", "[sea-nav] toured list cleared - all charted features are candidates again") sea_nav_tick() vik_draw() end
-- set the auto-resolve preference: "off" (hold for manual), "first", or a keyword list like "salvage,press" function sea_nav_resolve_set(s) s = (s or ""):gsub("^%s*(.-)%s*$", "%1") sea_nav.resolve = (s == "off") and "" or s SetVariable("seanav_resolve", sea_nav.resolve) ColourNote("cyan", "", "[sea-nav] auto-resolve " .. (sea_nav.resolve == "" and "OFF (hold at nodes, you resolve)" or ("preference: " .. sea_nav.resolve))) vik_draw() end
function OnPluginBroadcast(msg, id, name, text) if id ~= MIP_ID then return end local _, vmip = getvars() cp_accumulate(vmip.CPB) -- remember city-plan placements as they happen local realn = tonumber((split(vmip.CPLAN or "", "|"))[3]) or 0 if realn < cp_count() then -- a building was removed: our list is stale, resync cp_placed = {}; cp_accumulate(vmip.CPB); cp_save() end sea_nav_tick() -- Map tab isn't redrawn on every feed update (real-time grid redraws lagged the client); -- it refreshes when you click onto it. Other tabs update live as before. if tab ~= "Map" then vik_draw() end end
-- Modrsokn cooldown: fired by the trigger when the ability is used function mordsokn_used() mordsokn_at = os.time() SetVariable("mordsokn_at", tostring(mordsokn_at)) ColourNote("orange", "", "[Modrsokn] used - 3:00 cooldown") mordsokn_start_tick() end
-- self-rescheduling 1s repaint so the Stats-tab countdown ticks smoothly, stops when ready function mordsokn_start_tick() if mordsokn_ticking then return end mordsokn_ticking = true mordsokn_tick() end
function mordsokn_tick() local left = MORDSOKN_CD - (os.time() - mordsokn_at) if visible and tab == "Stats" then vik_draw() end if left > 0 then DoAfterSpecial(1, "mordsokn_tick()", 12) else mordsokn_ticking = false ColourNote("lime", "", "[Modrsokn] ready") if visible and tab == "Stats" then vik_draw() end end end
function vik_tick(state) if state == "on" then AddTimer("viking_keepalive", 0, 5, 0, "l", timer_flag.Enabled + timer_flag.Replace, "") SetVariable("tick", "1") else EnableTimer("viking_keepalive", false) SetVariable("tick", "0") end Note("[viking] keepalive 'l' every 5 min: " .. state) end
function OnPluginSaveState() if windowinfo then movewindow.save_state(WIN) end SetVariable("visible", visible and "1" or "0") SetVariable("tab", tab) end
function OnPluginInstall() AddTimer("viking_keepalive", 0, 5, 0, "l", timer_flag.Replace, "") if GetVariable("tick") == "1" then EnableTimer("viking_keepalive", true) end if os.time() - mordsokn_at < MORDSOKN_CD then mordsokn_start_tick() end -- resume a live cooldown vik_draw() end
function OnPluginEnable() vik_draw() end function OnPluginDisable() WindowShow(WIN, false) end
